/**
 * Utility functions for formatting LLM messages according to OpenTelemetry
 * Semantic Conventions v1.40.0 for gen_ai attributes.
 *
 * These formatters produce JSON strings for attributes like:
 * - gen_ai.system_instructions
 * - gen_ai.input.messages
 * - gen_ai.output.messages
 *
 * JSON schemas sourced from:
 * - https://opentelemetry.io/docs/specs/semconv/gen-ai/gen-ai-system-instructions.json
 * - https://opentelemetry.io/docs/specs/semconv/gen-ai/gen-ai-input-messages.json
 * - https://opentelemetry.io/docs/specs/semconv/gen-ai/gen-ai-output-messages.json
 */
/**
 * Formats system instructions for gen_ai.system_instructions attribute.
 *
 * @param system - System instruction as a plain string or an array of content blocks
 * @returns JSON string — a flat array of OTel part objects (no wrapping message)
 */
declare function formatSystemInstructions(system: string | Array<{
    type: string;
    text?: string;
    [key: string]: any;
}>): string;
/**
 * Formats chat messages for gen_ai.input.messages attribute.
 *
 * @param messages - Array of message objects with role and content
 * @param contentBlockMapper - Provider-specific function to map a content block to an OTel part
 * @returns JSON string — array of ChatMessage objects with role and typed parts
 */
declare function formatInputMessages(messages: Array<{
    role: string;
    content: string | Array<any>;
}>, contentBlockMapper: (block: any) => object, traceContent?: boolean): string;
/**
 * Formats a text completion prompt for gen_ai.input.messages attribute.
 *
 * @param prompt - The text prompt string
 * @returns JSON string — array with a single user ChatMessage
 */
declare function formatInputMessagesFromPrompt(prompt: string, traceContent?: boolean): string;
/**
 * Formats output content for gen_ai.output.messages attribute.
 *
 * @param content - Array of content blocks or string completion
 * @param stopReason - The stop reason from the LLM response
 * @param finishReasonMap - Mapping of provider-specific stop reasons to standard finish reasons
 * @param type - Type of completion: "chat", "generate_content", or "text_completion" (use GEN_AI_OPERATION_NAME_VALUE_* constants)
 * @param contentBlockMapper - Provider-specific function to map a content block to an OTel part
 * @returns JSON string — array with a single assistant OutputMessage
 */
declare function formatOutputMessage(content: Array<any> | string, stopReason: string | null, finishReasonMap: Record<string, string>, type: string, contentBlockMapper: (block: any) => object, traceContent?: boolean): string;

/**
 * Provider-specific content block mappers for OTel gen_ai attributes.
 *
 * Each function maps a single provider SDK content block to its
 * OTel-compliant part object, as defined in the gen_ai semantic conventions.
 *
 * These are passed as the `contentBlockMapper` parameter to
 * `formatInputMessages` and `formatOutputMessage`.
 */
/**
 * Maps a single Anthropic content block to its OTel-compliant part object.
 * Used by formatInputMessages, formatOutputMessage, and formatSystemInstructions.
 */
declare function mapAnthropicContentBlock(block: any): object;
/**
 * Maps a single OpenAI SDK content part to its OTel-compliant part object.
 * Used for input content parts in user messages.
 */
declare function mapOpenAIContentBlock(block: any): object;
/**
 * Maps a single Bedrock content block to its OTel-compliant part object.
 * Used by formatInputMessages and formatOutputMessage for all Bedrock providers.
 */
declare const mapBedrockContentBlock: (block: any) => object;
/**
 * Maps a single Vercel AI SDK content part to its OTel-compliant part object.
 *
 * Field names follow AI SDK v6:
 *   ToolCallPart:   toolCallId, toolName, input
 *   ToolResultPart: toolCallId, toolName, output (ToolResultOutput union)
 *   ImagePart:      image (DataContent | URL), optional mediaType
 *   FilePart:       data (DataContent | URL), mediaType (required)
 *   ReasoningPart:  text
 */
declare const mapAiSdkContentPart: (part: any) => any;
/**
 * Converts Vercel AI SDK message content to an array of OTel parts.
 * Accepts: plain string, array of SDK content parts, or a JSON-serialized array
 * (the AI SDK serializes content arrays as JSON strings in span attributes).
 */
declare const mapAiSdkMessageContent: (content: any) => any[];

export { formatInputMessages, formatInputMessagesFromPrompt, formatOutputMessage, formatSystemInstructions, mapAiSdkContentPart, mapAiSdkMessageContent, mapAnthropicContentBlock, mapBedrockContentBlock, mapOpenAIContentBlock };
